def get_manual_practice(track_id: str, filename: str) -> list[dict[str, Any]]:
    """Возвращает две последовательные практики только для нумерованных rich-уроков."""
    match = re.match(r"^(\d{2})\s+-\s+", filename)
    if match is None:
        return []

    lesson_number = int(match.group(1))
    practice_by_track = {
        FOUNDATIONS_TRACK: FOUNDATIONS_PRACTICE,
        DEEPER_TRACK: DEEPER_PRACTICE,
    }.get(track_id, {})
    return practice_by_track.get(lesson_number, [])
